Código
dataJoule = Array.from({length: 300}, (_, i) =&gt; {
  const tauPlot_us = 1 + i * (1000 - 1) / 299
  const tauPlot_s  = tauPlot_us * 1.0e-6
  const dT         = sigma * E_SI * E_SI * tauPlot_s / (rho * cp)
  return {
    tau_us: tauPlot_us,
    deltaT: dT
  }
})









