Código
t0    = t0_us
tau   = tau_us
tp    = tp_us
t_fin = t0 + tp
tiempo_total = Math.max(tiempo_total_us, t0 + 1.2 * tp, t0 + 4 * tau)

datos_rc = Array.from({length: 700}, (_, i) =&gt; {
  const t = (i / 699) * tiempo_total
  const pulso = (t &gt;= t0 && t &lt;= t_fin) ? 1 : 0

  let deltaV
  if (t &lt; t0) {
    deltaV = 0
  } else if (t &lt;= t_fin) {
    deltaV = Vmax * (1 - Math.exp(-(t - t0) / tau))
  } else {
    const deltaV_tp = Vmax * (1 - Math.exp(-tp / tau))
    deltaV = deltaV_tp * Math.exp(-(t - t_fin) / tau)
  }

  return { t, pulso, deltaV }
})

deltaV_tau  = Vmax * (1 - Math.exp(-1))
deltaV_tp   = Vmax * (1 - Math.exp(-tp / tau))
fraccion_tp = 100 * deltaV_tp / Vmax



































































